1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	const COMPONENT_BLOCK_SIZE = 3;
8	const COMPONENT_BLOCK_PRICE = 60;
9	
10	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune"]);
19	
20	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
21	
22	const sumBasePremiumsFor = (items: Item[]): number => {
23	  const componentCounts: Record<string, number> = {};
24	  let total = 0;
25	  for (const item of items) {
26	    if (COMPONENT_TYPES.has(item.type)) {
27	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
28	    } else {
29	      total += basePremiumOf(item);
30	    }
31	  }
32	  for (const [type, count] of Object.entries(componentCounts)) {
33	    if (count === COMPONENT_BLOCK_SIZE) {
34	      total += COMPONENT_BLOCK_PRICE;
35	    } else {
36	      total += count * BASE_PREMIUM_BY_TYPE[type];
37	    }
38	  }
39	  return total;
40	};
41	
42	const computePremium = (items: Item[]): number => {
43	  const base = sumBasePremiumsFor(items);
44	  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
45	  return withFirstInsurance + PROCESSING_FEE;
46	};
47	
48	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
49	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
50	const roundUpToGold = (amount: number): number =>
51	  Math.ceil(Math.round(amount * 1e6) / 1e6);
52	
53	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
54	  const results = scenario.steps.map((step) => ({
55	    premium: roundUpToGold(computePremium(step.items)),
56	  }));
57	  return { results };
58	};
59

